/* Display the consumer nodes, support ticket nodes, and transaction nodes, along with their opened ticket relationships and from relationships. */

MATCH p= (c:Consumer)-[*1..2]->()
RETURN p

/* Display the consumer nodes, support ticket nodes, and transaction nodes, along with their opened ticket relationships and from relationships. */

MATCH (c:Consumer)-[ot:OPENED_TICKET]->(st:SupportTicket),       (c)-[fr:FROM]->(t:Transaction)
