// ============================================================================
// SISTEMA DE RECOMENDAÇÃO HÍBRIDO - Score Ponderado
// ============================================================================

MATCH (target:Consumer {consumer_id: $consumer_consumer_id})

// =========================================================================
// ESTRATÉGIA 1: COLLABORATIVE FILTERING (Jornadas Similares)
// Score: 40% do total
// =========================================================================

// Encontrar consumers com jornadas similares
OPTIONAL MATCH (target)-[sim:SIMILAR_JOURNEY]-(similar:Consumer)
WHERE sim.similarity_score >= 0.1

// Produtos que similares compraram
OPTIONAL MATCH (similar)-[up:USES_PRODUCT]->(p1:Product)

// Que target NÃO comprou
WHERE NOT EXISTS {
    MATCH (target)-[:USES_PRODUCT]->(p1)
}

WITH target, p1,
     avg(sim.similarity_score) as avg_similarity,
     count(DISTINCT similar) as similar_users_bought,
     sum(up.count) as similar_purchase_count

// Score colaborativo = (similaridade média * 20) + (num usuários * 2)
WITH target, p1,
     (coalesce(avg_similarity, 0) * 20) + (coalesce(similar_users_bought, 0) * 2) as collab_score,
     avg_similarity,
     similar_users_bought

// =========================================================================
// ESTRATÉGIA 2: POPULARITY (Produtos Populares)
// Score: 20% do total
// =========================================================================

WITH target, p1, collab_score, avg_similarity, similar_users_bought

// Popularidade geral do produto
OPTIONAL MATCH (p1)<-[up_all:USES_PRODUCT]-()
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     count(up_all) as total_buyers

// Score de popularidade (normalizado)
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     coalesce(total_buyers, 0) * 0.1 as popularity_score,
     total_buyers

// =========================================================================
// ESTRATÉGIA 3: SEGMENTAÇÃO (Produtos do Perfil)
// Score: 15% do total
// =========================================================================

// Produtos populares no mesmo perfil (PRO ou não-PRO)
OPTIONAL MATCH (same_profile:Consumer {is_pro: target.is_pro})-[:USES_PRODUCT]->(p1)
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers,
     count(same_profile) as same_profile_buyers

// Score de perfil
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers,
     coalesce(same_profile_buyers, 0) * 0.3 as profile_score,
     same_profile_buyers

// =========================================================================
// ESTRATÉGIA 4: CATEGORIA DE INTERESSE (Produtos da mesma categoria)
// Score: 15% do total
// =========================================================================

// Ver categorias que target já comprou
OPTIONAL MATCH (target)-[:USES_PRODUCT]->(:Product)-[:HAS_TYPE]->(pt_interest:ProductType)
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers, profile_score, same_profile_buyers,
     collect(DISTINCT pt_interest) as target_categories

// Verificar se produto é de categoria de interesse
OPTIONAL MATCH (p1)-[:HAS_TYPE]->(pt:ProductType)
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers, profile_score, same_profile_buyers,
     pt, target_categories,
     CASE WHEN pt IN target_categories THEN 15 ELSE 0 END as category_boost

// =========================================================================
// ESTRATÉGIA 5: RECÊNCIA (Produtos recentemente populares)
// Score: 10% do total
// =========================================================================

// Verificar compras recentes do produto
OPTIONAL MATCH (p1)<-[:OF_PRODUCT]-(t:Transaction)
WHERE t.historical_at > datetime() - duration({days: 30})
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers, profile_score, same_profile_buyers,
     pt, category_boost,
     count(t) as recent_purchases

// Score de recência
WITH target, p1, collab_score, avg_similarity, similar_users_bought,
     popularity_score, total_buyers, profile_score, same_profile_buyers,
     pt, category_boost,
     coalesce(recent_purchases, 0) * 0.2 as recency_score,
     recent_purchases

// =========================================================================
// CÁLCULO DO SCORE FINAL PONDERADO
// =========================================================================

WITH p1, pt,
     collab_score,
     popularity_score,
     profile_score,
     category_boost,
     recency_score,
     avg_similarity,
     similar_users_bought,
     total_buyers,
     same_profile_buyers,
     recent_purchases,
     // Score final = soma ponderada de todos os componentes
     (collab_score * $PesoSimilaridade) +           // 40% - Collaborative Filtering
     (popularity_score * 0.20) +       // 20% - Popularidade
     (profile_score * 0.15) +          // 15% - Perfil similar
     (category_boost * 0.15) +         // 15% - Categoria de interesse
     (recency_score * 0.10) as final_score  // 10% - Recência

WHERE final_score > 0

// =========================================================================
// RETORNAR TOP 10 RECOMENDAÇÕES COM DETALHAMENTO
// =========================================================================

RETURN p1.product_id as product_id,
       p1.product_name as produto,
       pt.product_type_name as categoria,
       round(final_score * 10) / 10 as score_final,

       // Breakdown do score
       round(collab_score * 10) / 10 as score_colaborativo,
       round(popularity_score * 10) / 10 as score_popularidade,
       round(profile_score * 10) / 10 as score_perfil,
       round(category_boost * 10) / 10 as score_categoria,
       round(recency_score * 10) / 10 as score_recencia,

       // Métricas de suporte
       coalesce(similar_users_bought, 0) as usuarios_similares,
       coalesce(total_buyers, 0) as total_compradores,
       coalesce(same_profile_buyers, 0) as compradores_mesmo_perfil,
       coalesce(recent_purchases, 0) as compras_ultimos_30_dias,
       round(coalesce(avg_similarity, 0) * 100) / 100 as similaridade_media,

       // Classificação e confiança
       CASE
           WHEN final_score >= 50 THEN '🔴'
           WHEN final_score >= 30 THEN '🟠 '
           WHEN final_score >= 15 THEN '🟡 '
           ELSE '⚪ CONSIDERAR'
       END as prioridade
ORDER BY final_score DESC
LIMIT 10;

